  "recommendation": {
    "action": "refine",
    "reason": "The agent needs to be explicitly told that the input data will be available via stdin during execution, which should prevent it from outputting 'insufficient data' justifications. We also need to reinforce the strict JSON output constraint to prevent the 'invalid JSON' errors seen in iteration 11.",
    "new_prompt_text": "Write a self-contained, high-performance Python script that reads the problem instance from standard input (stdin). The script must implement an efficient optimization algorithm (e.g., Dijkstra, DP, or a heuristic search) to solve the problem described. Assume all necessary target data is provided via stdin. The script must calculate the result and print it in the following format:\nFINAL_ANSWER: <answer>\nJUSTIFICATION: <brief justification>\n\nReturn exactly one JSON object in this format:\n{\n  \"schema_name\": \"eywa_node_response\",\n  \"schema_version\": \"v1\",\n  \"orchestration_decision\": \"execute_locally\",\n  \"decision_notes\": \"string\",\n  \"response\": \"FINAL_ANSWER: <answer>\\nJUSTIFICATION: <brief justification>\",\n  \"result_type\": \"summary\"\n}"
  },
  "history_observations": [
    "Iteration 4, 6, 8, 10: Agent outputs 'insufficient data' because it thinks the prompt is missing the 1000 target pairs.",
    "Iteration 11: Agent fails JSON validation by using markdown fences.",
    "The plateau is caused by the agent's refusal to attempt a solution without seeing the data in the prompt text itself."
  ],
  "confidence": "high"
}
